import{_ as a,c as o,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Introducción al Plugin: Funciones y Riesgos | Antigravity Auth","description":"Aprende el valor central y las advertencias de riesgo del plugin Antigravity Auth. Accede a modelos Claude y Gemini 3 mediante Google OAuth, con soporte para balanceo de carga multi-cuenta.","frontmatter":{"title":"Introducción al Plugin: Funciones y Riesgos | Antigravity Auth","sidebarTitle":"¿Es Este Plugin Para Ti?","subtitle":"Conoce el Valor Central del Plugin Antigravity Auth","description":"Aprende el valor central y las advertencias de riesgo del plugin Antigravity Auth. Accede a modelos Claude y Gemini 3 mediante Google OAuth, con soporte para balanceo de carga multi-cuenta.","tags":["Inicio","Introducción al Plugin","OpenCode","Antigravity"],"order":1},"headers":[],"relativePath":"es/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md","filePath":"es/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"}'),n={name:"es/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"};function s(r,e,l,c,d,u){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="conoce-el-valor-central-del-plugin-antigravity-auth" tabindex="-1">Conoce el Valor Central del Plugin Antigravity Auth <a class="header-anchor" href="#conoce-el-valor-central-del-plugin-antigravity-auth" aria-label="Permalink to &quot;Conoce el Valor Central del Plugin Antigravity Auth&quot;">​</a></h1><p><strong>Antigravity Auth</strong> es un plugin de OpenCode que accede a la API de Antigravity mediante autenticación Google OAuth. Te permite usar tu cuenta de Google familiar para llamar a modelos avanzados como Claude Opus 4.5, Sonnet 4.5 y Gemini 3 Pro/Flash, sin necesidad de gestionar claves API. El plugin también ofrece balanceo de carga multi-cuenta, sistema de doble cuota y recuperación automática de sesiones, ideal para usuarios que necesitan modelos avanzados y gestión automatizada.</p><h2 id="que-aprenderas" tabindex="-1">Qué Aprenderás <a class="header-anchor" href="#que-aprenderas" aria-label="Permalink to &quot;Qué Aprenderás&quot;">​</a></h2><ul><li>Determinar si este plugin es adecuado para tu caso de uso</li><li>Conocer qué modelos de IA y funciones principales soporta el plugin</li><li>Entender los riesgos y precauciones al usar este plugin</li><li>Decidir si continuar con la instalación y configuración</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu Situación Actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu Situación Actual&quot;">​</a></h2><p>Quieres usar los modelos de IA más avanzados (como Claude Opus 4.5, Gemini 3 Pro), pero el acceso oficial está restringido. Buscas una forma confiable de acceder a estos modelos, y además deseas:</p><ul><li>No tener que gestionar manualmente múltiples claves API</li><li>Cambio automático de cuenta cuando encuentres límites de velocidad</li><li>Recuperación automática de conversaciones interrumpidas sin perder el contexto</li></ul><h2 id="idea-principal" tabindex="-1">Idea Principal <a class="header-anchor" href="#idea-principal" aria-label="Permalink to &quot;Idea Principal&quot;">​</a></h2><p><strong>Antigravity Auth</strong> es un plugin de OpenCode que accede a la API de Google Antigravity mediante <strong>autenticación Google OAuth</strong>, permitiéndote llamar a modelos de IA avanzados usando tu cuenta de Google familiar.</p><p>No actúa como proxy de todas las solicitudes, sino que <strong>intercepta y transforma</strong> tus solicitudes de llamada a modelos, las reenvía a la API de Antigravity, y luego convierte las respuestas de vuelta a un formato que OpenCode puede reconocer.</p><h2 id="funciones-principales" tabindex="-1">Funciones Principales <a class="header-anchor" href="#funciones-principales" aria-label="Permalink to &quot;Funciones Principales&quot;">​</a></h2><h3 id="modelos-soportados" tabindex="-1">Modelos Soportados <a class="header-anchor" href="#modelos-soportados" aria-label="Permalink to &quot;Modelos Soportados&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Serie de Modelos</th><th>Modelos Disponibles</th><th>Características</th></tr></thead><tbody><tr><td><strong>Claude</strong></td><td>Opus 4.5, Sonnet 4.5</td><td>Soporta modo de pensamiento extendido</td></tr><tr><td><strong>Gemini 3</strong></td><td>Pro, Flash</td><td>Integración con Google Search, pensamiento extendido</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Modo de Pensamiento (Thinking)</p><p>Los modelos Thinking realizan un &quot;pensamiento profundo&quot; antes de generar respuestas, mostrando el proceso de razonamiento. Puedes configurar el presupuesto de pensamiento para equilibrar calidad y velocidad de respuesta.</p></div><h3 id="balanceo-de-carga-multi-cuenta" tabindex="-1">Balanceo de Carga Multi-Cuenta <a class="header-anchor" href="#balanceo-de-carga-multi-cuenta" aria-label="Permalink to &quot;Balanceo de Carga Multi-Cuenta&quot;">​</a></h3><ul><li><strong>Soporta hasta 10 cuentas de Google</strong></li><li>Cambio automático a la siguiente cuenta cuando encuentres límites de velocidad (error 429)</li><li>Tres estrategias de selección de cuenta: sticky (fija), round-robin (rotación), hybrid (híbrida inteligente)</li></ul><h3 id="sistema-de-doble-cuota" tabindex="-1">Sistema de Doble Cuota <a class="header-anchor" href="#sistema-de-doble-cuota" aria-label="Permalink to &quot;Sistema de Doble Cuota&quot;">​</a></h3><p>El plugin accede simultáneamente a <strong>dos pools de cuota independientes</strong>:</p><ol><li><strong>Cuota Antigravity</strong>: De la API de Google Antigravity</li><li><strong>Cuota Gemini CLI</strong>: De Google Gemini CLI</li></ol><p>Cuando un pool está limitado, el plugin intenta automáticamente el otro pool, maximizando la utilización de cuota.</p><h3 id="recuperacion-automatica-de-sesiones" tabindex="-1">Recuperación Automática de Sesiones <a class="header-anchor" href="#recuperacion-automatica-de-sesiones" aria-label="Permalink to &quot;Recuperación Automática de Sesiones&quot;">​</a></h3><ul><li>Detecta fallos en llamadas de herramientas (como interrupciones con ESC)</li><li>Inyecta automáticamente tool_result sintético para evitar que la conversación se rompa</li><li>Soporta envío automático de &quot;continue&quot; para continuar la conversación</li></ul><h3 id="integracion-con-google-search" tabindex="-1">Integración con Google Search <a class="header-anchor" href="#integracion-con-google-search" aria-label="Permalink to &quot;Integración con Google Search&quot;">​</a></h3><p>Habilita búsqueda web para modelos Gemini, mejorando la precisión factual:</p><ul><li><strong>Modo Auto</strong>: El modelo decide si buscar según sea necesario</li><li><strong>Modo Always-on</strong>: Busca en cada solicitud</li></ul><h2 id="cuando-usar-este-plugin" tabindex="-1">Cuándo Usar Este Plugin <a class="header-anchor" href="#cuando-usar-este-plugin" aria-label="Permalink to &quot;Cuándo Usar Este Plugin&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Adecuado para estos escenarios</p><ul><li>Tienes múltiples cuentas de Google y quieres aumentar la cuota total</li><li>Necesitas usar modelos Thinking de Claude o Gemini 3</li><li>Quieres habilitar Google Search para modelos Gemini</li><li>No quieres gestionar claves API manualmente, prefieres autenticación OAuth</li><li>Encuentras límites de velocidad frecuentemente y quieres cambio automático de cuenta</li></ul></div><div class="warning custom-block"><p class="custom-block-title">No adecuado para estos escenarios</p><ul><li>Necesitas usar modelos no públicos de Google</li><li>Eres muy sensible a los riesgos de ToS de Google (ver advertencia de riesgos abajo)</li><li>Solo necesitas modelos básicos Gemini 1.5 o Claude 3 (las interfaces oficiales son más estables)</li><li>Tienes dificultades para abrir navegadores en entornos WSL, Docker, etc.</li></ul></div><h2 id="⚠️-advertencia-de-riesgos-importante" tabindex="-1">⚠️ Advertencia de Riesgos Importante <a class="header-anchor" href="#⚠️-advertencia-de-riesgos-importante" aria-label="Permalink to &quot;⚠️ Advertencia de Riesgos Importante&quot;">​</a></h2><p>Usar este plugin <strong>puede violar los Términos de Servicio de Google</strong>. Un pequeño número de usuarios ha reportado que sus cuentas de Google fueron <strong>suspendidas</strong> o <strong>shadow banned</strong> (acceso restringido sin notificación explícita).</p><h3 id="escenarios-de-alto-riesgo" tabindex="-1">Escenarios de Alto Riesgo <a class="header-anchor" href="#escenarios-de-alto-riesgo" aria-label="Permalink to &quot;Escenarios de Alto Riesgo&quot;">​</a></h3><ul><li>🚨 <strong>Cuentas de Google nuevas</strong>: Probabilidad extremadamente alta de suspensión</li><li>🚨 <strong>Cuentas con suscripción Pro/Ultra recién activada</strong>: Fácilmente marcadas y suspendidas</li></ul><h3 id="confirma-antes-de-usar" tabindex="-1">Confirma Antes de Usar <a class="header-anchor" href="#confirma-antes-de-usar" aria-label="Permalink to &quot;Confirma Antes de Usar&quot;">​</a></h3><ul><li>Esta es una <strong>herramienta no oficial</strong>, no respaldada por Google</li><li>Tu cuenta puede ser suspendida temporal o permanentemente</li><li>Asumes todos los riesgos de usar este plugin</li></ul><h3 id="recomendaciones" tabindex="-1">Recomendaciones <a class="header-anchor" href="#recomendaciones" aria-label="Permalink to &quot;Recomendaciones&quot;">​</a></h3><ul><li>Usa <strong>cuentas de Google maduras</strong>, no crees cuentas nuevas para este plugin</li><li>Evita usar cuentas importantes vinculadas a servicios críticos</li><li>Si tu cuenta es suspendida, no puedes apelar a través de este plugin</li></ul><div class="danger custom-block"><p class="custom-block-title">Seguridad de la Cuenta</p><p>Todos los tokens OAuth se almacenan localmente en <code>~/.config/opencode/antigravity-accounts.json</code>, no se suben a ningún servidor. Pero asegúrate de que tu computadora esté segura para prevenir fugas de tokens.</p></div><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de Esta Lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de Esta Lección&quot;">​</a></h2><p>Antigravity Auth es un potente plugin de OpenCode que te permite acceder a modelos avanzados Claude y Gemini 3 mediante Google OAuth. Ofrece balanceo de carga multi-cuenta, sistema de doble cuota, recuperación automática de sesiones y más, ideal para usuarios que necesitan modelos avanzados y gestión automatizada.</p><p>Pero ten en cuenta: <strong>usar este plugin conlleva riesgo de suspensión de cuenta</strong>. Por favor usa cuentas de Google no críticas y comprende los riesgos relacionados antes de continuar con la instalación.</p><h2 id="avance-de-la-siguiente-leccion" tabindex="-1">Avance de la Siguiente Lección <a class="header-anchor" href="#avance-de-la-siguiente-leccion" aria-label="Permalink to &quot;Avance de la Siguiente Lección&quot;">​</a></h2><blockquote><p>En la siguiente lección aprenderemos <strong><a href="/docs/opencodedocs/es/NoeFabris/opencode-antigravity-auth/start/quick-install/">Instalación Rápida</a></strong>.</p><p>Aprenderás:</p><ul><li>Completar la instalación del plugin en 5 minutos</li><li>Añadir tu primera cuenta de Google</li><li>Verificar la instalación exitosa</li></ul></blockquote>',42)])])}const m=a(n,[["render",s]]);export{g as __pageData,m as default};
